+    asx_grpc_service_add_unary(&svc, "Echo", echo_handler, NULL);
+    ASSERT_EQ(asx_grpc_server_add_service(&srv, &svc), ASX_OK);
+
+    asx_grpc_message_init(&req);
+    asx_grpc_message_set(&req, "ping", 4);
