+    /* Update existing */
+    ASSERT_EQ(asx_grpc_health_set(&health, "MyService", ASX_GRPC_HEALTH_SERVING), ASX_OK);
+    ASSERT_EQ(asx_grpc_health_check(&health, "MyService"), ASX_GRPC_HEALTH_SERVING);
+}
